  created() {
    const host = this.$store.state.config.api.host.includes("//") ? this.$store.state.config.api.host.split("//")[1] : null;
    if (host !== null) {
      ipcRenderer.invoke("ping", host).then(result => {
        if (result.alive) {
          this.ping = Math.round(result.avg) + " ms";
        } else {
          this.ping = "Unknown";
        }
      });
    }
  },
  computed: mapState({
    inLobby: state => {
      return state.lobby.lobbyType;
    }
  }),
  methods: {
    goHome() {
      this.$sound.template("OVERVIEW_CLICK");
      this.$router.push("/LoggedIn/home");
    },
    createLobby() {
      this.$sound.template("OVERVIEW_CLICK");
      const custom = this.selectedMode.custom;
      const isBotGame = this.selectedMode.name === this.$translate.text("PLAY_DATA_LOBBY_COOPVSAI");
      let lobbyType;
      if (isBotGame) {
        // 人机模式的 lobbyType 格式: BOT_{MAP}_{DIFFICULTY}
        lobbyType = `${this.selectedGameMap.code}_BOT_${this.selectedGameType.difficulty}`;
      } else {
        lobbyType = `${this.selectedGameMap.code}_${this.selectedGameType.code}`;
      }
      const router = this.$router;
      const lobbyData = {
        lobbyType: lobbyType,
        isCustom: custom,
        isBotGame: isBotGame,
        botDifficulty: isBotGame ? this.selectedGameType.difficulty : null
      };
      if (this.$store.state.lobby.owner) {
        this.$socket.sendLobbyMessage("LOBBY_CHANGE_TYPE", {
          data: lobbyData
        }, (response, error) => {
          if (error) {
            console.log("Flyback error:");
            console.log(error);
          }
          if (custom && this.$route.name !== "LobbyCustom") {
            router.push("/lobbyCustom");
          } else if (!custom && this.$route.name !== "Lobby") {
            router.push("/lobby");
          }
        });
      } else {
        this.$socket.sendSystemMessage("LOBBY_CREATE", {
          data: lobbyData
        }, (response, error) => {
          if (error) {
            console.log("Flyback error:");
            console.log(error);
          }
          if (custom) {
            router.push("/lobbyCustom");
          } else {
            router.push("/lobby");
          }
        });
      }
    },
    getModeInfoStyles() {
      return `background-image: url('${this.selectedGameMode.bgimage}'); background-size: cover; background-position: center;`;
    },
    selectMode(mode) {
      if (mode.disabled) return;
      if (this.selectedMode == mode) return;
      this.selectedMode = mode;
      if (this.selectedMode.gamemodes && this.selectedMode.gamemodes.length > 0) {
        this.selectedGameMode = this.selectedMode.gamemodes[0];
        if (this.selectedGameMode.maps && this.selectedGameMode.maps.length > 0) {
          this.selectedGameMap = this.selectedGameMode.maps[0];
          if (this.selectedGameMap.types && this.selectedGameMap.types.length > 0) {
            this.selectedGameType = this.selectedGameMap.types[0];
          }
        }
      }
      this.$sound.template("CORE_CLICK");
    },
    selectGameMode(gamemode) {
      if (this.selectedGameMode == gamemode) return;
      this.selectedGameMode = gamemode;
      if (this.selectedGameMode.maps && this.selectedGameMode.maps.length > 0) {
        this.selectedGameMap = this.selectedGameMode.maps[0];
        if (this.selectedGameMap.types && this.selectedGameMap.types.length > 0) {
          this.selectedGameType = this.selectedGameMap.types[0];
        }
      }
      this.$sound.template("CORE_CLICK");
    },
    selectGameMap(map) {
      if (this.selectedGameMap == map) return;
      this.selectedGameMap = map;
      if (this.selectedGameMap.types && this.selectedGameMap.types.length > 0) {
        this.selectedGameType = this.selectedGameMap.types[0];
      }
      this.$sound.template("CORE_CLICK");
    },
    selectGameType(type) {
      if (this.selectedGameType == type) return;
      this.selectedGameType = type;
      this.$sound.template("CORE_CLICK");
    },
    t(key) {
      return this.$translate.text(key);
